mapper.select:
/* 최근 알람 목록 조회(3건) */ select alarm_idx, site_id, device_id, device_type, std_date, alarm_code, alarm_type, alarm_msg, alarm_cfm_yn, alarm_cfm_date, alarm_cfm_uid, alarm_act_yn, alarm_note, reg_date, mod_date from tb_alarm where 1=1
and site_id = #{siteId }
order by std_date desc limit 0, 3

/* 알람 타입건수 조회 */
select 
	count(if(alarm_type=1, alarm_type, null)) as alert_cnt, 
	count(if(alarm_type=2, alarm_type, null)) as warning_cnt
from tb_alarm
where 1=1
and site_id = #{siteId }

and alarm_cfm_yn = #{alarmCfmYn }


and std_date between str_to_date(#{schTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{schTermTo },'%Y%m%d%H%i%s')

order std_date

/* 최근 알람 목록 조회(3건) */
select 
	a.alarm_idx, a.site_id, a.device_id, a.device_type, a.std_date, a.alarm_code, a.alarm_type, a.alarm_msg,
	a.alarm_cfm_yn, a.alarm_cfm_date, a.alarm_cfm_uid, a.alarm_act_yn, a.alarm_note, a.reg_date, a.mod_date
from tb_alarm a, tb_site b, tb_site_group c
where 1=1
and a.site_id = b.site_id
and b.site_grp_idx = c.site_grp_idx




and b.user_idx = #{userIdx}


and b.comp_idx = #{compIdx}


and b.site_grp_idx = #{siteGrpIdx}

and b.area_type = #{areaType}



and b.site_grp_idx = #{grpIdx}


and c.user_idx = #{userIdx}


and c.comp_idx = #{compIdx}


and c.site_grp_idx = #{siteGrpIdx}




and a.std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')

order by a.std_date desc
limit 0, 3
